import React, { useState } from 'react';
import {
  View,
  Text,
  StyleSheet,
  SafeAreaView,
  ScrollView,
  TextInput,
  TouchableOpacity,
  Alert,
  KeyboardAvoidingView,
  Platform,
} from 'react-native';
import { useNavigation } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import { RootStackParamList } from '../navigation/types';
import { colors, spacing, typography, borderRadius, shadows } from '../utils/constants';
import { SubscriptionCategory, BillingCycle, SubscriptionFormData } from '../types/subscription';
import { useSubscriptionStore } from '../store';
import walletServiceManager from '../services/walletService';
import { Button } from '../components/common/Button';
import { formatCurrency } from '../utils/formatting';

const AddSubscriptionScreen: React.FC = () => {
  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();
  const { addSubscription, isLoading } = useSubscriptionStore();

  const [formData, setFormData] = useState<SubscriptionFormData>({
    name: '',
    description: '',
    category: SubscriptionCategory.OTHER,
    price: 0,
    currency: 'USD',
    billingCycle: BillingCycle.MONTHLY,
    nextBillingDate: new Date(),
    isCryptoEnabled: false,
    cryptoToken: undefined,
    cryptoAmount: undefined,
  });

  const [selectedCategory, setSelectedCategory] = useState<SubscriptionCategory>(
    SubscriptionCategory.OTHER
  );
  const [selectedBillingCycle, setSelectedBillingCycle] = useState<BillingCycle>(
    BillingCycle.MONTHLY
  );

  const handleCategorySelect = (category: SubscriptionCategory) => {
    setSelectedCategory(category);
    setFormData((prev) => ({ ...prev, category }));
  };

  const handleBillingCycleSelect = (cycle: BillingCycle) => {
    setSelectedBillingCycle(cycle);
    setFormData((prev) => ({ ...prev, billingCycle: cycle }));
  };

  const handleInputChange = (
    field: keyof SubscriptionFormData,
    value: string | number | boolean
  ) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const handleSubmit = async () => {
    if (!formData.name.trim()) {
      Alert.alert('Error', 'Please enter a subscription name');
      return;
    }

    if (formData.price <= 0) {
      Alert.alert('Error', 'Please enter a valid price');
      return;
    }

    try {
      await addSubscription(formData);

      if (formData.isCryptoEnabled) {
        Alert.alert(
          'Success!',
          'Subscription added successfully! Would you like to set up crypto payments now?',
          [
            { text: 'Later', onPress: () => navigation.goBack() },
            {
              text: 'Setup Crypto',
              onPress: () => navigation.navigate('CryptoPayment', { subscriptionId: 'new' }),
            },
          ]
        );
      } else {
        Alert.alert('Success', 'Subscription added successfully!', [
          { text: 'OK', onPress: () => navigation.goBack() },
        ]);
      }
    } catch (error) {
      Alert.alert('Error', 'Failed to add subscription. Please try again.');
    }
  };

  const handleCancel = () => {
    if (
      formData.name.trim() ||
      (formData.description && formData.description.trim()) ||
      formData.price > 0
    ) {
      Alert.alert('Discard Changes', 'Are you sure you want to discard your changes?', [
        { text: 'Cancel', style: 'cancel' },
        { text: 'Discard', style: 'destructive', onPress: () => navigation.goBack() },
      ]);
    } else {
      navigation.goBack();
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <KeyboardAvoidingView
        style={styles.keyboardAvoidingView}
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}>
        <ScrollView style={styles.scrollView}>
          <View style={styles.header}>
            <View style={styles.headerContent}>
              <TouchableOpacity onPress={handleCancel} style={styles.cancelButton}>
                <Text style={styles.cancelText}>Cancel</Text>
              </TouchableOpacity>
              <Text style={styles.title}>Add Subscription</Text>
              <View style={styles.placeholderButton} />
            </View>
            <Text style={styles.subtitle}>Track your new subscription</Text>
          </View>

          <View style={styles.form}>
            <View style={styles.section}>
              <Text style={styles.sectionTitle}>Basic Information</Text>
              <View style={styles.inputGroup}>
                <Text style={styles.label}>Name *</Text>
                <TextInput
                  style={styles.textInput}
                  value={formData.name}
                  onChangeText={(text) => handleInputChange('name', text)}
                  placeholder="Enter subscription name"
                  placeholderTextColor={colors.textSecondary}
                  autoFocus
                />
              </View>

              <View style={styles.inputGroup}>
                <Text style={styles.label}>Description (Optional)</Text>
                <TextInput
                  style={[styles.textInput, styles.textArea]}
                  value={formData.description}
                  onChangeText={(text) => handleInputChange('description', text)}
                  placeholder="Enter description"
                  placeholderTextColor={colors.textSecondary}
                  multiline
                  numberOfLines={3}
                  textAlignVertical="top"
                />
              </View>
            </View>

            <View style={styles.section}>
              <Text style={styles.sectionTitle}>Category</Text>
              <View style={styles.categoryGrid}>
                {Object.values(SubscriptionCategory).map((category) => (
                  <TouchableOpacity
                    key={category}
                    style={[
                      styles.categoryItem,
                      selectedCategory === category && styles.categoryItemSelected,
                    ]}
                    onPress={() => handleCategorySelect(category)}>
                    <Text
                      style={[
                        styles.categoryText,
                        selectedCategory === category && styles.categoryTextSelected,
                      ]}>
                      {category.charAt(0).toUpperCase() + category.slice(1)}
                    </Text>
                  </TouchableOpacity>
                ))}
              </View>
            </View>

            <View style={styles.section}>
              <Text style={styles.sectionTitle}>Billing Details</Text>
              <View style={styles.inputGroup}>
                <Text style={styles.label}>Price *</Text>
                <View style={styles.priceInputContainer}>
                  <Text style={styles.currencySymbol}>$</Text>
                  <TextInput
                    style={styles.priceInput}
                    value={formData.price > 0 ? formData.price.toString() : ''}
                    onChangeText={(text) => {
                      const numValue = parseFloat(text) || 0;
                      handleInputChange('price', numValue);
                    }}
                    placeholder="0.00"
                    placeholderTextColor={colors.textSecondary}
                    keyboardType="decimal-pad"
                  />
                </View>
              </View>

              <View style={styles.inputGroup}>
                <Text style={styles.label}>Billing Cycle</Text>
                <View style={styles.billingCycleContainer}>
                  {Object.values(BillingCycle).map((cycle) => (
                    <TouchableOpacity
                      key={cycle}
                      style={[
                        styles.billingCycleItem,
                        selectedBillingCycle === cycle && styles.billingCycleItemSelected,
                      ]}
                      onPress={() => handleBillingCycleSelect(cycle)}>
                      <Text
                        style={[
                          styles.billingCycleText,
                          selectedBillingCycle === cycle && styles.billingCycleTextSelected,
                        ]}>
                        {cycle.charAt(0).toUpperCase() + cycle.slice(1)}
                      </Text>
                    </TouchableOpacity>
                  ))}
                </View>
              </View>
            </View>

            <View style={styles.section}>
              <Text style={styles.sectionTitle}>Crypto Options</Text>
              <View style={styles.cryptoOption}>
                <TouchableOpacity
                  style={styles.cryptoToggle}
                  onPress={() => handleInputChange('isCryptoEnabled', !formData.isCryptoEnabled)}>
                  <View
                    style={[
                      styles.toggleSwitch,
                      formData.isCryptoEnabled && styles.toggleSwitchActive,
                    ]}>
                    <View
                      style={[
                        styles.toggleKnob,
                        formData.isCryptoEnabled && styles.toggleKnobActive,
                      ]}
                    />
                  </View>
                </TouchableOpacity>
                <Text style={styles.cryptoLabel}>Enable crypto payments</Text>
              </View>
            </View>
          </View>
        </ScrollView>

        <View style={styles.footer}>
          <Button
            title="Add Subscription"
            onPress={handleSubmit}
            loading={isLoading}
            fullWidth
            size="large"
          />
        </View>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: colors.background,
  },
  keyboardAvoidingView: {
    flex: 1,
  },
  scrollView: {
    flex: 1,
  },
  header: {
    padding: spacing.lg,
    paddingBottom: spacing.md,
  },
  headerContent: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: spacing.xs,
  },
  cancelButton: {
    padding: spacing.sm,
  },
  cancelText: {
    ...typography.body,
    color: colors.primary,
    fontWeight: '500',
  },
  placeholderButton: {
    width: 60,
  },
  title: {
    ...typography.h1,
    color: colors.text,
    textAlign: 'center',
  },
  subtitle: {
    ...typography.body,
    color: colors.textSecondary,
    textAlign: 'center',
  },
  form: {
    padding: spacing.lg,
    paddingTop: 0,
  },
  section: {
    marginBottom: spacing.xl,
  },
  sectionTitle: {
    ...typography.h3,
    color: colors.text,
    marginBottom: spacing.md,
  },
  inputGroup: {
    marginBottom: spacing.md,
  },
  label: {
    ...typography.body,
    color: colors.text,
    marginBottom: spacing.xs,
    fontWeight: '500',
  },
  textInput: {
    backgroundColor: colors.surface,
    padding: spacing.md,
    borderRadius: borderRadius.md,
    borderWidth: 1,
    borderColor: colors.border,
    color: colors.text,
    ...typography.body,
  },
  textArea: {
    height: 80,
    textAlignVertical: 'top',
  },
  priceInputContainer: {
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: colors.surface,
    borderRadius: borderRadius.md,
    borderWidth: 1,
    borderColor: colors.border,
    paddingHorizontal: spacing.md,
  },
  currencySymbol: {
    ...typography.h3,
    color: colors.textSecondary,
    marginRight: spacing.sm,
  },
  priceInput: {
    flex: 1,
    paddingVertical: spacing.md,
    color: colors.text,
    ...typography.h3,
    fontWeight: '600',
  },
  categoryGrid: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: spacing.sm,
  },
  categoryItem: {
    paddingHorizontal: spacing.md,
    paddingVertical: spacing.sm,
    borderRadius: borderRadius.full,
    backgroundColor: colors.surface,
    borderWidth: 1,
    borderColor: colors.border,
  },
  categoryItemSelected: {
    backgroundColor: colors.primary,
    borderColor: colors.primary,
  },
  categoryText: {
    ...typography.caption,
    color: colors.text,
  },
  categoryTextSelected: {
    color: colors.text,
    fontWeight: '600',
  },
  billingCycleContainer: {
    flexDirection: 'row',
    gap: spacing.sm,
  },
  billingCycleItem: {
    flex: 1,
    paddingVertical: spacing.sm,
    paddingHorizontal: spacing.md,
    borderRadius: borderRadius.md,
    backgroundColor: colors.surface,
    borderWidth: 1,
    borderColor: colors.border,
    alignItems: 'center',
  },
  billingCycleItemSelected: {
    backgroundColor: colors.primary,
    borderColor: colors.primary,
  },
  billingCycleText: {
    ...typography.caption,
    color: colors.text,
  },
  billingCycleTextSelected: {
    color: colors.text,
    fontWeight: '600',
  },
  cryptoOption: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: spacing.md,
  },
  cryptoToggle: {
    padding: spacing.xs,
  },
  toggleSwitch: {
    width: 50,
    height: 28,
    backgroundColor: colors.border,
    borderRadius: borderRadius.full,
    padding: 2,
  },
  toggleSwitchActive: {
    backgroundColor: colors.primary,
  },
  toggleKnob: {
    width: 24,
    height: 24,
    backgroundColor: colors.text,
    borderRadius: borderRadius.full,
  },
  toggleKnobActive: {
    transform: [{ translateX: 22 }],
  },
  cryptoLabel: {
    ...typography.body,
    color: colors.text,
  },
  footer: {
    padding: spacing.lg,
    paddingTop: spacing.md,
    borderTopWidth: 1,
    borderTopColor: colors.border,
    backgroundColor: colors.background,
  },
});

export default AddSubscriptionScreen;

import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  SafeAreaView,
  ScrollView,
  TextInput,
  TouchableOpacity,
  Alert,
  ActivityIndicator,
  KeyboardAvoidingView,
  Platform,
} from 'react-native';
import { useNavigation, useRoute } from '@react-navigation/native';
import { colors, spacing, typography, borderRadius, shadows } from '../utils/constants';
import { Button } from '../components/common/Button';
import { Card } from '../components/common/Card';
import walletServiceManager, { TokenBalance, GasEstimate } from '../services/walletService';

interface RouteParams {
  subscriptionId?: string;
}

const CryptoPaymentScreen: React.FC = () => {
  const navigation = useNavigation();
  const route = useRoute();
  const { subscriptionId } = (route.params as RouteParams) || {};

  // Handle case when no subscriptionId is provided
  useEffect(() => {
    if (!subscriptionId) {
      console.log('No subscriptionId provided, proceeding with general crypto setup');
    }
  }, [subscriptionId]);

  const [selectedToken, setSelectedToken] = useState<string>('ETH');
  const [amount, setAmount] = useState<string>('');
  const [recipientAddress, setRecipientAddress] = useState<string>('');
  const [selectedProtocol, setSelectedProtocol] = useState<'superfluid' | 'sablier'>('superfluid');
  const [gasEstimate, setGasEstimate] = useState<GasEstimate | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isEstimatingGas, setIsEstimatingGas] = useState(false);

  const [availableTokens, setAvailableTokens] = useState<TokenBalance[]>([]);
  const [connection, setConnection] = useState<any>(null);

  useEffect(() => {
    loadWalletData();
  }, []);

  useEffect(() => {
    if (amount && recipientAddress && connection) {
      estimateGas();
    }
  }, [amount, recipientAddress, connection]);

  const loadWalletData = async () => {
    try {
      const conn = walletServiceManager.getConnection();
      if (!conn) {
        Alert.alert('Error', 'Please connect a wallet first');
        navigation.goBack();
        return;
      }

      setConnection(conn);
      const balances = await walletServiceManager.getTokenBalances(conn.address, conn.chainId);
      setAvailableTokens(balances);

      // Set default recipient to connected wallet address
      setRecipientAddress(conn.address);
    } catch (error) {
      console.error('Failed to load wallet data:', error);
      Alert.alert('Error', 'Failed to load wallet data');
    }
  };

  const estimateGas = async () => {
    if (!connection || !amount || !recipientAddress) return;

    try {
      setIsEstimatingGas(true);
      const estimate = await walletServiceManager.estimateGas(
        connection.address,
        recipientAddress,
        amount,
        connection.chainId
      );
      setGasEstimate(estimate);
    } catch (error) {
      console.error('Failed to estimate gas:', error);
    } finally {
      setIsEstimatingGas(false);
    }
  };

  const handleTokenSelect = (tokenSymbol: string) => {
    setSelectedToken(tokenSymbol);
  };

  const handleProtocolSelect = (protocol: 'superfluid' | 'sablier') => {
    setSelectedProtocol(protocol);
  };

  const validateForm = (): boolean => {
    if (!amount || parseFloat(amount) <= 0) {
      Alert.alert('Error', 'Please enter a valid amount');
      return false;
    }

    if (!recipientAddress || recipientAddress.length !== 42) {
      Alert.alert('Error', 'Please enter a valid recipient address');
      return false;
    }

    if (!selectedToken) {
      Alert.alert('Error', 'Please select a token');
      return false;
    }

    return true;
  };

  const handleCreateStream = async () => {
    if (!validateForm()) return;

    try {
      setIsLoading(true);
      let streamId: string;

      if (selectedProtocol === 'superfluid') {
        streamId = await walletServiceManager.createSuperfluidStream(
          selectedToken,
          amount,
          recipientAddress,
          connection.chainId
        );
      } else {
        const startTime = Math.floor(Date.now() / 1000);
        const stopTime = startTime + 30 * 24 * 60 * 60; // 30 days from now
        streamId = await walletServiceManager.createSablierStream(
          selectedToken,
          amount,
          startTime,
          stopTime,
          recipientAddress,
          connection.chainId
        );
      }

      Alert.alert('Success!', `Stream created successfully!\nStream ID: ${streamId}`, [
        { text: 'OK', onPress: () => navigation.goBack() },
      ]);
    } catch (error) {
      console.error('Failed to create stream:', error);
      Alert.alert('Error', 'Failed to create stream. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  const getTokenIcon = (symbol: string): string => {
    const icons: Record<string, string> = {
      ETH: '≡ƒö╖',
      MATIC: '≡ƒƒú',
      USDC: '≡ƒÆÖ',
      ARB: '≡ƒö╡',
    };
    return icons[symbol] || '≡ƒ¬Ö';
  };

  const getProtocolDescription = (protocol: 'superfluid' | 'sablier'): string => {
    const descriptions = {
      superfluid: 'Continuous streaming payments with real-time settlement',
      sablier: 'Scheduled payments with time-locked streams',
    };
    return descriptions[protocol];
  };

  const getProtocolIcon = (protocol: 'superfluid' | 'sablier'): string => {
    return protocol === 'superfluid' ? '≡ƒîè' : 'ΓÅ░';
  };

  return (
    <SafeAreaView style={styles.container}>
      <KeyboardAvoidingView
        style={styles.keyboardAvoidingView}
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}>
        <ScrollView style={styles.scrollView}>
          <View style={styles.header}>
            <Text style={styles.title}>
              {subscriptionId ? 'Crypto Payment Setup' : 'Crypto Payment Configuration'}
            </Text>
            <Text style={styles.subtitle}>
              {subscriptionId
                ? 'Configure streaming payments for this subscription'
                : 'Set up crypto payment streams for your subscriptions'}
            </Text>
          </View>

          {/* Token Selection */}
          <Card variant="elevated" padding="large">
            <Text style={styles.sectionTitle}>Select Payment Token</Text>
            <View style={styles.tokenGrid}>
              {availableTokens.map((token, index) => (
                <TouchableOpacity
                  key={index}
                  style={[
                    styles.tokenOption,
                    selectedToken === token.symbol && styles.tokenOptionSelected,
                  ]}
                  onPress={() => handleTokenSelect(token.symbol)}>
                  <Text style={styles.tokenIcon}>{getTokenIcon(token.symbol)}</Text>
                  <Text style={styles.tokenSymbol}>{token.symbol}</Text>
                  <Text style={styles.tokenBalance}>{parseFloat(token.balance).toFixed(4)}</Text>
                </TouchableOpacity>
              ))}
            </View>
          </Card>

          {/* Payment Amount */}
          <Card variant="elevated" padding="large">
            <Text style={styles.sectionTitle}>Payment Amount</Text>
            <View style={styles.amountInput}>
              <Text style={styles.currencySymbol}>{selectedToken}</Text>
              <TextInput
                style={styles.amountTextInput}
                value={amount}
                onChangeText={setAmount}
                placeholder="0.00"
                placeholderTextColor={colors.textSecondary}
                keyboardType="decimal-pad"
              />
            </View>
            <Text style={styles.amountDescription}>Amount to stream per payment cycle</Text>
          </Card>

          {/* Recipient Address */}
          <Card variant="elevated" padding="large">
            <Text style={styles.sectionTitle}>Recipient Address</Text>
            <TextInput
              style={styles.addressInput}
              value={recipientAddress}
              onChangeText={setRecipientAddress}
              placeholder="0x..."
              placeholderTextColor={colors.textSecondary}
              autoCapitalize="none"
              autoCorrect={false}
            />
            <Text style={styles.addressDescription}>
              The address that will receive the payments
            </Text>
          </Card>

          {/* Protocol Selection */}
          <Card variant="elevated" padding="large">
            <Text style={styles.sectionTitle}>Payment Protocol</Text>
            <View style={styles.protocolOptions}>
              <TouchableOpacity
                style={[
                  styles.protocolOption,
                  selectedProtocol === 'superfluid' && styles.protocolOptionSelected,
                ]}
                onPress={() => handleProtocolSelect('superfluid')}>
                <Text style={styles.protocolIcon}>≡ƒîè</Text>
                <Text style={styles.protocolName}>Superfluid</Text>
                <Text style={styles.protocolDescription}>Continuous streaming payments</Text>
              </TouchableOpacity>

              <TouchableOpacity
                style={[
                  styles.protocolOption,
                  selectedProtocol === 'sablier' && styles.protocolOptionSelected,
                ]}
                onPress={() => handleProtocolSelect('sablier')}>
                <Text style={styles.protocolIcon}>ΓÅ░</Text>
                <Text style={styles.protocolName}>Sablier</Text>
                <Text style={styles.protocolDescription}>Time-locked payment streams</Text>
              </TouchableOpacity>
            </View>
          </Card>

          {/* Gas Estimation */}
          {gasEstimate && (
            <Card variant="elevated" padding="large">
              <Text style={styles.sectionTitle}>Gas Estimation</Text>
              <View style={styles.gasInfo}>
                <View style={styles.gasRow}>
                  <Text style={styles.gasLabel}>Gas Limit:</Text>
                  <Text style={styles.gasValue}>{gasEstimate.gasLimit}</Text>
                </View>
                <View style={styles.gasRow}>
                  <Text style={styles.gasLabel}>Gas Price:</Text>
                  <Text style={styles.gasValue}>{gasEstimate.gasPrice} Gwei</Text>
                </View>
                <View style={styles.gasRow}>
                  <Text style={styles.gasLabel}>Estimated Cost:</Text>
                  <Text style={styles.gasValue}>
                    {parseFloat(gasEstimate.estimatedCost).toFixed(6)} {selectedToken}
                  </Text>
                </View>
              </View>
            </Card>
          )}

          {/* Create Stream Button */}
          <View style={styles.footer}>
            <Button
              title={isLoading ? 'Creating Stream...' : 'Create Payment Stream'}
              onPress={handleCreateStream}
              loading={isLoading}
              variant="crypto"
              fullWidth
              size="large"
            />
          </View>
        </ScrollView>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: colors.background,
  },
  keyboardAvoidingView: {
    flex: 1,
  },
  scrollView: {
    flex: 1,
  },
  header: {
    padding: spacing.lg,
    paddingBottom: spacing.md,
  },
  title: {
    ...typography.h1,
    color: colors.text,
    marginBottom: spacing.xs,
  },
  subtitle: {
    ...typography.body,
    color: colors.textSecondary,
  },
  sectionTitle: {
    ...typography.h3,
    color: colors.text,
    marginBottom: spacing.md,
  },
  tokenGrid: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: spacing.sm,
  },
  tokenOption: {
    flex: 1,
    minWidth: 100,
    alignItems: 'center',
    padding: spacing.md,
    backgroundColor: colors.surface,
    borderRadius: borderRadius.md,
    borderWidth: 1,
    borderColor: colors.border,
  },
  tokenOptionSelected: {
    backgroundColor: colors.primary,
    borderColor: colors.primary,
  },
  tokenIcon: {
    fontSize: 24,
    marginBottom: spacing.xs,
  },
  tokenSymbol: {
    ...typography.body,
    color: colors.text,
    fontWeight: '600',
    marginBottom: spacing.xs,
  },
  tokenBalance: {
    ...typography.caption,
    color: colors.textSecondary,
  },
  amountInput: {
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: colors.surface,
    borderRadius: borderRadius.md,
    borderWidth: 1,
    borderColor: colors.border,
    paddingHorizontal: spacing.md,
    marginBottom: spacing.sm,
  },
  currencySymbol: {
    ...typography.h2,
    color: colors.textSecondary,
    marginRight: spacing.sm,
  },
  amountTextInput: {
    flex: 1,
    paddingVertical: spacing.md,
    color: colors.text,
    ...typography.h2,
    fontWeight: '600',
  },
  amountDescription: {
    ...typography.caption,
    color: colors.textSecondary,
  },
  addressInput: {
    backgroundColor: colors.surface,
    padding: spacing.md,
    borderRadius: borderRadius.md,
    borderWidth: 1,
    borderColor: colors.border,
    color: colors.text,
    ...typography.body,
    fontFamily: 'monospace',
    marginBottom: spacing.sm,
  },
  addressDescription: {
    ...typography.caption,
    color: colors.textSecondary,
  },
  protocolOptions: {
    gap: spacing.md,
  },
  protocolOption: {
    padding: spacing.md,
    backgroundColor: colors.surface,
    borderRadius: borderRadius.md,
    borderWidth: 1,
    borderColor: colors.border,
  },
  protocolOptionSelected: {
    backgroundColor: colors.accent,
